        pos = max(0, min(position, self._size))
        # Insert all characters at once
        for ch in text:
            self._content.insert(pos, ch)
            pos += 1
        self._size += len(text)

    def delete(self, start, end):
        start = max(0, min(start, self._size))
        end = max(0, min(end, self._size))
        if start >= end:
            return

        # Determine actual slice to remove
        if start == end:
            return

        # Remove characters from the list
        # We'll delete from start to end (end exclusive)
        for i in range(end - 1, start - 1, -1):
            self._content.pop(i)
        self._size -= (end - start)

    def find(self, text):
        if not text:
            # Empty match at index 0 (or wherever, but here we return 0)
            return 0

        i = 0
        n = len(self._content)
        m = len(text)

        while i <= n - m:
            j = 0
            while j < m and self._content[i + j] == text[j]:
                j += 1
            if j == m:
                return i
            i += 1
        return -1

    @property
    def content(self):
        return ''.join(self._content)
