    """
    Compute the nth Fibonacci number using recursion with memoization.

    Args:
        n (int): 0-indexed position (0 ≤ n ≤ 50).

    Returns:
        int: The nth Fibonacci number.

    Raises:
        ValueError: If n is not a non-negative integer or out of range.
    """
    # Validate input
    if not isinstance(n, int):
        raise ValueError("n must be an integer.")
    if n < 0:
        raise ValueError("n must be non-negative.")
    if n > 50:
        raise ValueError("n must be between 0 and 50 inclusive.")

    # Memoization storage
    memo = {}

    @functools.lru_cache(maxsize=None)
    def fib(k: int) -> int:
        if k == 0:
            return 0
        if k == 1:
            return 1
        return fib(k - 1) + fib(k - 2)

    return fib(n)
