        raise ValueError("n must be an integer.")
    if n < 0 or n > 50:
        raise ValueError("n must be between 0 and 50 inclusive.")

    memo = {}

    def fib(k: int) -> int:
        if k in memo:
            return memo[k]
        if k == 0:
            result = 0
        elif k == 1:
            result = 1
        else:
