    def __init__(self, item):
        self.item = item
        self.next = None


class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, item):
        """Adds an item to the end of the linked list."""
        # If list is empty, the new node becomes the head
        if self.head is None:
            self.head = Node(item)
            return

        # Traverse to the end and set next to new node
        current = self.head
        while current.next is not None:
            current = current.next
        current.next = Node(item)

    def search(self, item):
        """Returns True if item exists in the list, False otherwise."""
        current = self.head
        while current is not None:
            if current.item == item:
                return True
            current = current.next
        return False

    def remove(self, item):
        """Removes the first occurrence of item. Returns True if found/removed, else False."""
        # Case 1: Removing the head
        if self.head is None:
            return False

        if self.head.item == item:
            self.head = self.head.next
            return True

        # Case 2: Removing a node that is not the head
        current = self.head
        while current.next is not None:
            if current.next.item == item:
                current.next = current.next.next
                return True
            current = current.next

        # If no item found
