def factorial(n: any):
    # Check if n is a number
    if not isinstance(n, (int, float)):
        return "Input must be an integer."

    # Allow int subclasses (e.g., numpy.int64) but not floats
    if isinstance(n, float):
        if n != int(n):
            # Non-integer float (e.g., 3.5)
            return "Input must be an integer."
        # Otherwise, treat as int
        n = int(n)

    # Check for negative
    if n < 0:
        return "Factorial is not defined for negative numbers."

    # Recursive base case and step
    def fact(k: int) -> int:
        if k == 0 or k == 1:
            return 1
        return k * fact(k - 1)

    return fact(n)
```

